#include<bits/stdc++.h>
using namespace std;
struct node{int jj,time;}a[10005];
int n,m,b[10005];
bool cmp(node x,node y){return x.jj>y.jj;}
int main(void){
	cin>>n;
	for(int i=1;i<=n;i++)cin>>a[i].time;
	for(int i=1;i<=n;i++)cin>>a[i].jj;
    sort(a+1,a+1+n,cmp);
	for(int i=1;i<=n;i++){
		bool flag=false;
		for(int j=a[i].time;j>=1;j--){if(!b[j]){b[j]=1,flag=true;break;}}
		if(flag)m+=a[i].jj;
	}cout<<m;
	return false;
}
